const payload = $json.body ?? $json;
const request = payload.request;
const brand = payload.brand;
const schema = {
  type: 'object',
  additionalProperties: false,
  required: ['hook','title','caption','cta','hashtags','visualDirection','slides','script','storyFrames','adaptationNotes'],
  properties: {
    hook: { type: 'string' },
    title: { type: 'string' },
    caption: { type: 'string' },
    cta: { type: 'string' },
    hashtags: { type: 'array', items: { type: 'string' }, maxItems: 15 },
    visualDirection: { type: 'string' },
    slides: { type: 'array', maxItems: 12, items: { type: 'object', additionalProperties: false, required: ['title','body'], properties: { title: { type: 'string' }, body: { type: 'string' } } } },
    script: { type: 'array', maxItems: 12, items: { type: 'object', additionalProperties: false, required: ['scene','visual','voiceover'], properties: { scene: { type: 'string' }, visual: { type: 'string' }, voiceover: { type: 'string' } } } },
    storyFrames: { type: 'array', maxItems: 10, items: { type: 'object', additionalProperties: false, required: ['headline','body','interaction'], properties: { headline: { type: 'string' }, body: { type: 'string' }, interaction: { type: 'string' } } } },
    adaptationNotes: { type: 'array', maxItems: 10, items: { type: 'string' } }
  }
};
const revision = request.revisionInstructions ? `\nINSTRUÇÕES DE REVISÃO: ${request.revisionInstructions}\nVERSÃO ANTERIOR: ${JSON.stringify(request.output)}` : '';
const prompt = `Crie uma peça de conteúdo em português do Brasil.\nMARCA: ${brand.name}\nNICHO: ${brand.niche}\nSITE: ${brand.websiteUrl || 'não informado'}\nINSTAGRAM: ${brand.instagramHandle || 'não informado'}\nFORMATO: ${request.contentType}\nOBJETIVO: ${request.objective}\nCANAL: ${request.channel}\nBRIEFING: ${request.brief}${revision}\n\nRegras: seja específico, evite clichês, preserve coerência com o formato, use hashtags relevantes sem excesso e deixe vazias as estruturas que não pertencem ao formato.`;
return [{ json: {
  callbackUrl: payload.callbackUrl,
  requestId: request.id,
  openaiBody: {
    model: 'gpt-5.6-luna',
    store: false,
    input: [
      { role: 'system', content: [{ type: 'input_text', text: 'Você é estrategista e redator sênior da MODO. Entregue conteúdo publicável, claro, útil e orientado ao objetivo da marca.' }] },
      { role: 'user', content: [{ type: 'input_text', text: prompt }] }
    ],
    text: { format: { type: 'json_schema', name: 'modo_generated_content', description: 'Conteúdo estruturado para revisão no portal MODO', strict: true, schema } }
  }
} }];

const source = $('Build OpenAI Payload').item.json;
const response = $json;
if (response.error) {
  return [{ json: { callbackUrl: source.callbackUrl, callbackBody: { status: 'failed', error: response.error.message || JSON.stringify(response.error), providerRunId: response.id } } }];
}
let text = response.output_text;
if (!text && Array.isArray(response.output)) {
  for (const item of response.output) {
    for (const content of item.content ?? []) {
      if (content.type === 'output_text' && content.text) text = content.text;
    }
  }
}
if (!text) {
  return [{ json: { callbackUrl: source.callbackUrl, callbackBody: { status: 'failed', error: 'A OpenAI não retornou conteúdo estruturado.', providerRunId: response.id } } }];
}
try {
  return [{ json: { callbackUrl: source.callbackUrl, callbackBody: { status: 'completed', output: JSON.parse(text), providerRunId: response.id } } }];
} catch (error) {
  return [{ json: { callbackUrl: source.callbackUrl, callbackBody: { status: 'failed', error: `Resposta JSON inválida: ${error.message}`, providerRunId: response.id } } }];
}
